import React from "react";
import { useState, useEffect, useRef, useCallback } from "react";
import { db, doc, setDoc, onSnapshot } from "./firebase";


// ─── CUSTOM HOOK: useLocalStorage + Firestore Sync ───────────────────────────
// Sanitize: Firestore rejects undefined values
function sanitizeForFirestore(val) {
  if (val === undefined) return null;
  if (val === null || typeof val !== "object") return val;
  if (Array.isArray(val)) return val.map(sanitizeForFirestore);
  const out = {};
  for (const k in val) {
    if (Object.prototype.hasOwnProperty.call(val, k)) {
      const v = val[k];
      out[k] = v === undefined ? null : (typeof v === "object" && v !== null ? sanitizeForFirestore(v) : v);
    }
  }
  return out;
}

function useLocalStorage(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      return initialValue;
    }
  });

  const ref = useRef(storedValue);
  ref.current = storedValue;
  const firestoreLoaded = useRef(false);

  // ── Firestore real-time sync ──
  useEffect(() => {
    const docRef = doc(db, "state", key);
    const unsub = onSnapshot(docRef, (snap) => {
      if (snap.exists()) {
        const remoteVal = snap.data().value;
        ref.current = remoteVal;
        setStoredValue(remoteVal);
        try { window.localStorage.setItem(key, JSON.stringify(remoteVal)); } catch(e) {}
      }
      firestoreLoaded.current = true;
    }, (error) => {
      console.error("Firestore sync error:", key, error);
      firestoreLoaded.current = true;
    });
    return unsub;
  }, [key]);

  const setValue = useCallback((value) => {
    try {
      const valueToStore = value instanceof Function ? value(ref.current) : value;
      ref.current = valueToStore;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
      // Only write to Firestore after initial load to prevent overwriting with stale data
      if (firestoreLoaded.current) {
        const docRef = doc(db, "state", key);
        setDoc(docRef, { value: sanitizeForFirestore(valueToStore) }).catch(err => console.error("Firestore write error:", key, err));
      }
    } catch (error) {
      console.log(error);
    }
  }, [key]);

  return [storedValue, setValue];
}

// ─── HOOK: useLocalOnly (localStorage only, NO Firestore sync) ───────────────
// Usado para dados individuais por navegador (sessão do usuário, evento selecionado)
function useLocalOnly(key, initialValue) {
  const [storedValue, setStoredValue] = useState(() => {
    try {
      const item = window.localStorage.getItem(key);
      return item ? JSON.parse(item) : initialValue;
    } catch (error) {
      return initialValue;
    }
  });
  const ref = useRef(storedValue);
  ref.current = storedValue;
  const setValue = useCallback((value) => {
    try {
      const valueToStore = value instanceof Function ? value(ref.current) : value;
      ref.current = valueToStore;
      setStoredValue(valueToStore);
      window.localStorage.setItem(key, JSON.stringify(valueToStore));
    } catch (error) {
      console.log(error);
    }
  }, [key]);
  return [storedValue, setValue];
}

// Hook para escutar mudanças no localStorage de outras abas
function useStorageSync(key, setter) {
  useEffect(() => {
    const handler = (e) => {
      if (e.key === key && e.newValue) {
        try { setter(JSON.parse(e.newValue)); } catch(err) {}
      }
    };
    window.addEventListener("storage", handler);
    return () => window.removeEventListener("storage", handler);
  }, [key, setter]);
}

// ── MIGRAÇÃO SÍNCRONA: tipo "treinador" → "equipe" (executada uma vez antes do React montar) ──
(function migrarDadosLegacy() {
  try {
    // Migra usuário logado
    const raw = window.localStorage.getItem("atl_usuario");
    if (raw) {
      const u = JSON.parse(raw);
      if (u && u.tipo === "treinador") {
        u.tipo = "equipe";
        window.localStorage.setItem("atl_usuario", JSON.stringify(u));
      }
    }
    // Migra solicitações de vínculo (origem + aprovadorTipo)
    const rawVinc = window.localStorage.getItem("atl_vinculo_sol");
    if (rawVinc) {
      const arr = JSON.parse(rawVinc);
      let changed = false;
      const migrado = arr.map(s => {
        let n = s;
        if (s.origem === "treinador") { n = { ...n, origem: "equipe" }; changed = true; }
        if (s.aprovadorTipo === "treinador_atual") { n = { ...n, aprovadorTipo: "equipe_atual" }; changed = true; }
        return n;
      });
      if (changed) window.localStorage.setItem("atl_vinculo_sol", JSON.stringify(migrado));
    }
    // Migra solicitações de recuperação
    const rawRec = window.localStorage.getItem("atl_recuperacao");
    if (rawRec) {
      const arr = JSON.parse(rawRec);
      if (Array.isArray(arr) && arr.some(s => s.tipo === "treinador")) {
        window.localStorage.setItem("atl_recuperacao", JSON.stringify(
          arr.map(s => s.tipo === "treinador" ? { ...s, tipo: "equipe" } : s)
        ));
      }
    }
    // Migra inscrições (treinadorCadastro -> equipeCadastroId)
    const rawInsc = window.localStorage.getItem("atl_inscricoes");
    if (rawInsc) {
      const arr = JSON.parse(rawInsc);
      if (Array.isArray(arr) && arr.some(s => s.treinadorCadastro !== undefined)) {
        window.localStorage.setItem("atl_inscricoes", JSON.stringify(
          arr.map(s => {
            if (s.treinadorCadastro !== undefined) {
              const { treinadorCadastro, ...rest } = s;
              return { ...rest, equipeCadastroId: treinadorCadastro };
            }
            return s;
          })
        ));
      }
    }
    // Migra recordes (adiciona escopo geográfico)
    const rawRecordes = window.localStorage.getItem("atl_recordes");
    if (rawRecordes) {
      const arr = JSON.parse(rawRecordes);
      let changed = false;
      const migrated = arr.map(tipo => {
        // Migra escopo
        let t = tipo;
        if (!t.escopo) { t = { ...t, escopo: "estado", pais: "Brasil", estado: "MG", municipio: null }; changed = true; }
        // Migra registros para formato detentores[]
        if (t.registros && t.registros.some(r => !Array.isArray(r.detentores))) {
          t = { ...t, registros: t.registros.map(r => {
            if (Array.isArray(r.detentores)) return r;
            changed = true;
            const { atleta, equipe, atletaId, ano, local, competicaoId, competicaoNome, atletasRevezamento, ...base } = r;
            return { ...base, detentores: [{ atleta: atleta || "", equipe: equipe || "", atletaId: atletaId || null,
              ano: ano || "", local: local || "", competicaoId: competicaoId || null, competicaoNome: competicaoNome || "",
              atletasRevezamento: atletasRevezamento || null }] };
          })};
        }
        return t;
      });
      if (changed) window.localStorage.setItem("atl_recordes", JSON.stringify(migrated));
    }
  } catch(e) { console.warn("Migração dados legados:", e); }
})();

