// Retorna a composição de uma prova combinada a partir do seu ID
// Ex: "M_adulto_decatlo" → { nome, provas: [...], totalProvas }
function getComposicaoCombinada(provaId) {
  const partes = provaId.split("_");
  const sexo = partes[0]; // M ou F
  const sufixo = partes[partes.length - 1]; // decatlo, heptatlo, etc.
  const comp = COMPOSICAO_COMBINADAS[sufixo];
  if (!comp) return null;
  // Tetratlo tem provas diferentes por sexo
  const provas = comp.provas || (sexo === "M" ? comp.provasM : comp.provasF) || [];
  return {
    nome: comp.nome,
    totalProvas: provas.length,
    provas: provas,
  };
}

// ─── COMBINED EVENT ENGINE ──────────────────────────────────────────────────
// Responsável por gerar provas-filha, inscrever/remover atletas em cascata
// ═══════════════════════════════════════════════════════════════════════════════
// RECORD HELPER — Utilitários para formato detentores[]
// Formato novo: { ..., marca, detentores: [{ atleta, equipe, atletaId, ano, local, competicaoId, competicaoNome, atletasRevezamento }] }
// Formato antigo: { ..., marca, atleta, equipe, atletaId, ano, local, ... }
// ═══════════════════════════════════════════════════════════════════════════════
const RecordHelper = {
  // Retorna array de detentores (compatível com formato antigo e novo)
  getDetentores(reg) {
    if (!reg) return [];
    if (Array.isArray(reg.detentores) && reg.detentores.length > 0) return reg.detentores;
    // Formato antigo → converte
    if (reg.atleta || reg.atletaId) {
      return [{ atleta: reg.atleta || "", equipe: reg.equipe || "", atletaId: reg.atletaId || null,
        ano: reg.ano || "", local: reg.local || "",
        competicaoId: reg.competicaoId || null, competicaoNome: reg.competicaoNome || "",
        atletasRevezamento: reg.atletasRevezamento || null }];
    }
    return [];
  },

  // Retorna o primeiro detentor (para leituras simples / backward compat)
  getPrimeiro(reg) {
    const d = this.getDetentores(reg);
    return d[0] || { atleta: "", equipe: "", atletaId: null, ano: "", local: "" };
  },

  // Texto do(s) atleta(s) para exibição
  getAtletaTexto(reg) {
    const dets = this.getDetentores(reg);
    if (dets.length === 0) return "—";
    return dets.map(d => {
      if (d.atletasRevezamento && d.atletasRevezamento.filter(Boolean).length > 0) {
        return d.atletasRevezamento.filter(Boolean).join(", ");
      }
      return d.atleta || "—";
    }).join(" / ");
  },

  // Texto da(s) equipe(s) para exibição
  getEquipeTexto(reg) {
    const dets = this.getDetentores(reg);
    if (dets.length === 0) return "—";
    const eqs = [...new Set(dets.map(d => d.equipe).filter(Boolean))];
    return eqs.join(" / ") || "—";
  },

  // Texto do(s) ano(s) para exibição
  getAnoTexto(reg) {
    const dets = this.getDetentores(reg);
    if (dets.length === 0) return "—";
    const anos = [...new Set(dets.map(d => d.ano).filter(Boolean))];
    return anos.join(" / ") || "—";
  },

  // Texto do(s) local(is) para exibição
  getLocalTexto(reg) {
    const dets = this.getDetentores(reg);
    if (dets.length === 0) return "—";
    const locs = [...new Set(dets.map(d => d.local).filter(Boolean))];
    return locs.join(" / ") || "—";
  },

  // Migra um registro do formato antigo para o novo
  migrar(reg) {
    if (!reg) return reg;
    if (Array.isArray(reg.detentores)) return reg; // já migrado
    const { atleta, equipe, atletaId, ano, local, competicaoId, competicaoNome, atletasRevezamento, ...base } = reg;
    const detentor = { atleta: atleta || "", equipe: equipe || "", atletaId: atletaId || null,
      ano: ano || "", local: local || "",
      competicaoId: competicaoId || null, competicaoNome: competicaoNome || "",
      atletasRevezamento: atletasRevezamento || null };
    return { ...base, detentores: [detentor] };
  },

  // Cria um novo registro no formato detentores[]
  criar({ id, categoriaId, sexo, provaId, provaNome, marca, unidade, fonte, marcasComponentes, detentor }) {
    return {
      id: id || `r_${Date.now()}_${Math.random().toString(36).slice(2,6)}`,
      categoriaId, sexo, provaId, provaNome, marca: String(marca), unidade: unidade || "s",
      fonte: fonte || "manual", marcasComponentes: marcasComponentes || null,
      detentores: [detentor],
    };
  },

  // Verifica se tem detentores de revezamento
  temRevezamento(reg) {
    const dets = this.getDetentores(reg);
    return dets.some(d => d.atletasRevezamento && d.atletasRevezamento.filter(Boolean).length > 0);
  },
};

const CombinedEventEngine = {

  // Gera os IDs das provas componentes para uma prova combinada dentro de um evento
  // Retorna array de { id, nome, tipo, unidade, dia, ordem, combinadaId }
  gerarProvasComponentes(combinadaProvaId, eventoId) {
    const comp = getComposicaoCombinada(combinadaProvaId);
    if (!comp) return [];
    return comp.provas.map((p, idx) => ({
      id: `${eventoId}_COMB_${combinadaProvaId}_${idx}_${p.sufixo}`,
      provaOriginalSufixo: p.sufixo,
      nome: p.nome,
      nomeCombinada: comp.nome,
      tipo: p.tipo,
      unidade: p.unidade,
      dia: p.dia,
      ordem: idx + 1,
      totalProvas: comp.totalProvas,
      combinadaId: combinadaProvaId,
      origemCombinada: true,
      grupo: `${comp.nome}`,
    }));
  },

  // Inscreve um atleta em todas as provas componentes de uma combinada
  // Retorna array de inscrições a serem adicionadas
  inscreverAtletaNasComponentes(atletaId, combinadaProvaId, eventoId, dadosBase, provasComponentes) {
    if (!provasComponentes || provasComponentes.length === 0) return [];
    const baseTs = Date.now();
    return provasComponentes.map((pc, idx) => ({
      id: `${eventoId}_${atletaId}_COMB_${pc.id}_${baseTs + idx}`,
      eventoId,
      atletaId,
      provaId: pc.id,
      combinadaId: combinadaProvaId,
      origemCombinada: true,
      categoria: dadosBase.categoria,
      categoriaId: dadosBase.categoriaId,
      categoriaOficial: dadosBase.categoriaOficial,
      categoriaOficialId: dadosBase.categoriaOficialId,
      sexo: dadosBase.sexo,
      data: new Date().toISOString(),
      inscritoPorId: dadosBase.inscritoPorId,
      inscritoPorNome: dadosBase.inscritoPorNome,
      inscritoPorTipo: dadosBase.inscritoPorTipo,
      equipeCadastro: dadosBase.equipeCadastro,
      equipeCadastroId: dadosBase.equipeCadastroId,
      // Metadados da componente
      ordemNaCombinada: pc.ordem,
      nomeCombinada: pc.nomeCombinada,
      provaComponenteNome: pc.nome,
    }));
  },

  // Verifica se uma inscrição é protegida (oriunda de combinada)
  isInscricaoProtegida(inscricao) {
    return inscricao && inscricao.origemCombinada === true;
  },

  // Remove todas as inscrições de componentes quando atleta é removido da combinada
  getInscricoesComponentesParaRemover(inscricoes, atletaId, combinadaProvaId, eventoId) {
    return inscricoes.filter(i =>
      i.eventoId === eventoId &&
      i.atletaId === atletaId &&
      i.combinadaId === combinadaProvaId &&
      i.origemCombinada === true
    ).map(i => i.id);
  },
};


