// Busca binária em tabela CBAt: encontra os pontos para uma marca de pista (menor tempo = mais pontos)
function cbatLookupTrack(tabela, tempoSegundos) {
  if (!tabela || tabela.length === 0) return 0;
  var t = parseFloat(tempoSegundos);
  if (isNaN(t)) return 0;
  // Tabela ordenada por marca asc, pontos desc (mais rápido = mais pontos)
  // Se tempo <= primeiro (mais rápido), retorna pontos máximo
  if (t <= tabela[0][0]) return tabela[0][1];
  // Se tempo >= último (mais lento), retorna pontos mínimo
  if (t >= tabela[tabela.length - 1][0]) return tabela[tabela.length - 1][1];
  // Busca binária: encontrar o intervalo [i, i+1] onde tabela[i][0] <= t < tabela[i+1][0]
  var lo = 0, hi = tabela.length - 1;
  while (lo < hi - 1) {
    var mid = Math.floor((lo + hi) / 2);
    if (tabela[mid][0] <= t) lo = mid;
    else hi = mid;
  }
  // Se a marca digitada existe exatamente na tabela, retorna seus pontos
  if (tabela[lo][0] === t) return tabela[lo][1];
  // Para pista: se o tempo está entre dois valores, arredonda para o MAIS LENTO (menos pontos)
  return tabela[hi][1];
}

// Calcula pontos usando fórmula WA (World Athletics)
// constantes: { a, b, c, tipo: "track"|"jump"|"throw" }
// valor: marca numérica (segundos para pista, metros para saltos/lançamentos)
function calcularPontosWA(constantes, valor) {
  if (!constantes || valor == null || isNaN(valor)) return 0;
  var a = constantes.a, b = constantes.b, c = constantes.c;
  var diff;
  if (constantes.tipo === "track") {
    // Pista: pontos = floor(a × (b - tempo)^c) — menor tempo = mais pontos
    diff = b - valor;
    if (diff <= 0) return 0;
  } else if (constantes.tipo === "jump") {
    // Saltos: resultado em metros no sistema, converter para centímetros para a fórmula
    var valorCm = valor * 100;
    diff = valorCm - b;
    if (diff <= 0) return 0;
  } else if (constantes.tipo === "throw") {
    // Arremessos/Lançamentos: resultado em metros
    diff = valor - b;
    if (diff <= 0) return 0;
  } else {
    return 0;
  }
  return Math.floor(a * Math.pow(diff, c));
}

