// ═══════════════════════════════════════════════════════════════════════════
// COMPONENTE: PAINEL DA EQUIPE
// ═══════════════════════════════════════════════════════════════════════════

function TelaPainelEquipe({ 
  usuarioLogado, 
  setTela, 
  logout,
  atletas, 
  inscricoes,
  eventos,
  equipes,
  historicoAcoes 
}) {
  const { equipe, permissoes } = usuarioLogado;

  // Verificar permissão
  const temPermissao = (permissao) => {
    return permissoes && permissoes.includes(permissao);
  };

  // Filtrar dados da equipe
  const atletasDaEquipe = (atletas || []).filter(a => a.equipeId === equipe.id);
  
  const inscricoesDaEquipe = (inscricoes || []).filter(i => 
    atletasDaEquipe.some(a => a.id === i.atletaId)
  );

  const auditoriaRecente = (historicoAcoes || [])
    .filter(a => a.equipeId === equipe.id)
    .sort((a, b) => new Date(b.data || b.timestamp) - new Date(a.data || a.timestamp))
    .slice(0, 5);

  // Estatísticas
  const totalMembros = (equipe.membros || []).length;
  const eventosAtivos = (eventos || []).filter(e => 
    !e.statusAprovacao || e.statusAprovacao === 'aprovado'
  ).length;
  const [buscaAtlEq, setBuscaAtlEq] = useState("");

  return (
    <div style={styles.page}>
      {/* Header */}
      <div style={{
        background: 'linear-gradient(135deg, #1976D2 0%, #d4a500 100%)',
        padding: 32,
        borderRadius: 12,
        marginBottom: 32,
        color: '#000'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
          <div>
            <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 8, opacity: 0.8 }}>
              🏅 PAINEL DA EQUIPE
            </div>
            <h1 style={{ fontSize: 36, fontWeight: 700, marginBottom: 8 }}>
              {equipe.nome}
            </h1>
            <div style={{ fontSize: 16, opacity: 0.9 }}>
              {equipe.sigla && `${equipe.sigla} • `}
              {equipe.cidade}, {equipe.estado}
            </div>
          </div>
          <button
            onClick={logout}
            style={{
              background: 'rgba(0,0,0,0.2)',
              color: '#000',
              border: 'none',
              padding: '10px 20px',
              borderRadius: 8,
              cursor: 'pointer',
              fontWeight: 600,
              fontSize: 14
            }}
          >
            🚪 Sair
          </button>
        </div>

        {/* Info do Usuário Logado */}
        <div style={{
          marginTop: 20,
          padding: 16,
          background: 'rgba(0,0,0,0.1)',
          borderRadius: 8,
          fontSize: 14
        }}>
          <div style={{ fontWeight: 600, marginBottom: 4 }}>
            👤 Logado como: {usuarioLogado?.nome}
          </div>
          {usuarioLogado?.cargo && (
            <div style={{ opacity: 0.9 }}>
              {usuarioLogado?.cargo}
            </div>
          )}
        </div>
      </div>

      {/* Estatísticas */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
        gap: 20,
        marginBottom: 32
      }}>
        <div style={{
          background: '#0D0E12',
          border: '2px solid #1976D2',
          borderRadius: 12,
          padding: 24,
          textAlign: 'center'
        }}>
          <div style={{ fontSize: 48, fontWeight: 700, color: '#1976D2', marginBottom: 8 }}>
            {atletasDaEquipe.length}
          </div>
          <div style={{ color: '#aaa', fontSize: 14, fontWeight: 600 }}>
            ATLETAS
          </div>
        </div>

        <div style={{
          background: '#0D0E12',
          border: '2px solid #88aaff',
          borderRadius: 12,
          padding: 24,
          textAlign: 'center'
        }}>
          <div style={{ fontSize: 48, fontWeight: 700, color: '#88aaff', marginBottom: 8 }}>
            {inscricoesDaEquipe.length}
          </div>
          <div style={{ color: '#aaa', fontSize: 14, fontWeight: 600 }}>
            INSCRIÇÕES
          </div>
        </div>

        <div style={{
          background: '#0D0E12',
          border: '2px solid #7cfc7c',
          borderRadius: 12,
          padding: 24,
          textAlign: 'center'
        }}>
          <div style={{ fontSize: 48, fontWeight: 700, color: '#7cfc7c', marginBottom: 8 }}>
            {totalMembros}
          </div>
          <div style={{ color: '#aaa', fontSize: 14, fontWeight: 600 }}>
            TREINADORES
          </div>
        </div>

        <div style={{
          background: '#0D0E12',
          border: '2px solid #ff6b9d',
          borderRadius: 12,
          padding: 24,
          textAlign: 'center'
        }}>
          <div style={{ fontSize: 48, fontWeight: 700, color: '#ff6b9d', marginBottom: 8 }}>
            {eventosAtivos}
          </div>
          <div style={{ color: '#aaa', fontSize: 14, fontWeight: 600 }}>
            EVENTOS ATIVOS
          </div>
        </div>
      </div>

      {/* Ações Rápidas */}
      <div style={{
        background: '#0D0E12',
        border: '1px solid #1E2130',
        borderRadius: 12,
        padding: 32,
        marginBottom: 32
      }}>
        <h3 style={{ color: '#1976D2', marginBottom: 24, fontSize: 20 }}>
          ⚡ Ações Rápidas
        </h3>
        
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
          gap: 16
        }}>
          {temPermissao('cadastrar_atleta') && (
            <button
              style={{
                ...styles.btnPrimary,
                padding: 20,
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 16
              }}
              onClick={() => setTela('cadastrar-atleta')}
            >
              <div style={{ fontSize: 32 }}>➕</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  Cadastrar Atleta
                </div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>
                  Adicionar novo atleta à equipe
                </div>
              </div>
            </button>
          )}

          {temPermissao('inscrever_competicao') && (
            <button
              style={{
                ...styles.btnSecondary,
                padding: 20,
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 16
              }}
              onClick={() => setTela('eventos')}
            >
              <div style={{ fontSize: 32 }}>📝</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  Inscrever em Evento
                </div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>
                  Ver eventos e fazer inscrições
                </div>
              </div>
            </button>
          )}

          {temPermissao('ver_resultados') && (
            <button
              style={{
                ...styles.btnGhost,
                padding: 20,
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 16
              }}
              onClick={() => setTela('resultados')}
            >
              <div style={{ fontSize: 32 }}>🏆</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  Ver Resultados
                </div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>
                  Consultar resultados das provas
                </div>
              </div>
            </button>
          )}

          {temPermissao('gerenciar_equipe') && (
            <button
              style={{
                ...styles.btnGhost,
                padding: 20,
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 16,
                borderColor: '#7cfc7c'
              }}
              onClick={() => setTela('gerenciar-membros')}
            >
              <div style={{ fontSize: 32 }}>👨‍🏫</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  Gerenciar Membros
                </div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>
                  Adicionar e configurar membros
                </div>
              </div>
            </button>
          )}

          {temPermissao('ver_auditoria') && (
            <button
              style={{
                ...styles.btnGhost,
                padding: 20,
                textAlign: 'left',
                display: 'flex',
                alignItems: 'center',
                gap: 16,
                borderColor: '#88aaff'
              }}
              onClick={() => setTela('auditoria')}
            >
              <div style={{ fontSize: 32 }}>📊</div>
              <div>
                <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>
                  Ver Auditoria
                </div>
                <div style={{ fontSize: 12, opacity: 0.8 }}>
                  Histórico de ações da equipe
                </div>
              </div>
            </button>
          )}
        </div>
      </div>

      {/* Duas Colunas */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 32 }}>
        
        {/* Atletas Recentes */}
        <div style={{
          background: '#0D0E12',
          border: '1px solid #1E2130',
          borderRadius: 12,
          padding: 24
        }}>
          <h3 style={{ color: '#1976D2', marginBottom: 20, fontSize: 18 }}>
            👥 Atletas da Equipe
          </h3>
          
          {atletasDaEquipe.length === 0 ? (
            <div style={{ textAlign: 'center', padding: 40, color: '#666' }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>👤</div>
              <div style={{ fontSize: 14 }}>Nenhum atleta cadastrado</div>
            </div>
          ) : (
            <>
            <input type="text" value={buscaAtlEq} onChange={e => setBuscaAtlEq(e.target.value)} placeholder="🔍 Buscar atleta..." style={{ ...styles.input, padding:"6px 12px", fontSize:12, marginBottom:8, width:"100%" }} />
            <div style={{ display: 'grid', gap: 8, maxHeight:280, overflowY:"auto" }}>
              {atletasDaEquipe.filter(a => {
                if (!buscaAtlEq) return true;
                return (a.nome||"").toLowerCase().includes(buscaAtlEq.toLowerCase());
              }).map(atleta => (
                <div key={atleta.id} style={{
                  padding: 10,
                  background: '#141720',
                  border: '1px solid #1E2130',
                  borderRadius: 8
                }}>
                  <div style={{ color: '#fff', fontWeight: 600, marginBottom: 2, fontSize:13 }}>
                    {atleta.nome}
                  </div>
                  <div style={{ color: '#888', fontSize: 11 }}>
                    {atleta.categoria || '-'} • {atleta.sexo === 'M' ? 'Masculino' : 'Feminino'}
                  </div>
                </div>
              ))}
            </div>
            <div style={{ color:"#555", fontSize:11, marginTop:6 }}>{atletasDaEquipe.length} atleta(s)</div>
            </>
          )}
        </div>

        {/* Atividade Recente */}
        <div style={{
          background: '#0D0E12',
          border: '1px solid #1E2130',
          borderRadius: 12,
          padding: 24
        }}>
          <h3 style={{ color: '#1976D2', marginBottom: 20, fontSize: 18 }}>
            📋 Atividade Recente
          </h3>
          
          {auditoriaRecente.length === 0 ? (
            <div style={{ textAlign: 'center', padding: 40, color: '#666' }}>
              <div style={{ fontSize: 48, marginBottom: 12 }}>📊</div>
              <div style={{ fontSize: 14 }}>Nenhuma atividade registrada</div>
            </div>
          ) : (
            <div style={{ display: 'grid', gap: 12 }}>
              {auditoriaRecente.map(registro => (
                <div key={registro.id} style={{
                  padding: 12,
                  background: '#141720',
                  border: '1px solid #1E2130',
                  borderRadius: 8
                }}>
                  <div style={{ color: '#fff', fontSize: 13, marginBottom: 4 }}>
                    {registro.acao}{registro.detalhe ? `: ${registro.detalhe}` : ""}
                  </div>
                  <div style={{ color: '#888', fontSize: 11 }}>
                    por {registro.nomeUsuario || "—"} •{' '}
                    {new Date(registro.data || registro.timestamp).toLocaleString('pt-BR', {
                      day: '2-digit',
                      month: '2-digit',
                      hour: '2-digit',
                      minute: '2-digit'
                    })}
                  </div>
                </div>
              ))}
              
              {temPermissao('ver_auditoria') && (
                <button
                  style={{
                    ...styles.btnGhost,
                    fontSize: 13,
                    padding: 10
                  }}
                  onClick={() => setTela('auditoria')}
                >
                  Ver histórico completo →
                </button>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Avisos de Permissões */}
      {permissoes && permissoes.length < 3 && (
        <div style={{
          marginTop: 32,
          padding: 20,
          background: '#2a2010',
          border: '1px solid #1976D244',
          borderRadius: 12,
          color: '#1976D2'
        }}>
          <div style={{ fontWeight: 600, marginBottom: 8 }}>
            ℹ️ Permissões Limitadas
          </div>
          <div style={{ fontSize: 14, opacity: 0.9 }}>
            Você tem acesso limitado ao sistema. Entre em contato com um administrador 
            da equipe para solicitar mais permissões.
          </div>
        </div>
      )}
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════════════
// COMPONENTE: GERENCIAR TREINADORES SUBORDINADOS
// ═══════════════════════════════════════════════════════════════════════════

function TelaGerenciarMembros({ usuarioLogado, setTela, equipes, atualizarEquipe, registrarAcao }) {
  const { equipe } = usuarioLogado;
  const [modo, setModo] = useState('lista'); // lista | novo | editar
  const [equipeSelecionada, setEquipeSelecionada] = useState(null);
  const [form, setForm] = useState({
    nome: '',
    email: '',
    senha: '',
    cpf: '',
    telefone: '',
    cargo: '',
    permissoes: []
  });
  const [erros, setErros] = useState({});

  const PERMISSOES_DISPONIVEIS = [
    { id: 'cadastrar_atleta', nome: 'Cadastrar Atletas', descricao: 'Adicionar novos atletas' },
    { id: 'editar_atleta', nome: 'Editar Atletas', descricao: 'Modificar dados dos atletas' },
    { id: 'excluir_atleta', nome: 'Excluir Atletas', descricao: 'Remover atletas' },
    { id: 'inscrever_competicao', nome: 'Inscrever em Competições', descricao: 'Inscrever atletas em eventos' },
    { id: 'cancelar_inscricao', nome: 'Cancelar Inscrições', descricao: 'Cancelar inscrições' },
    { id: 'ver_resultados', nome: 'Ver Resultados', descricao: 'Visualizar resultados' },
    { id: 'gerenciar_equipe', nome: 'Gerenciar Equipe', descricao: 'Adicionar/remover membros' },
    { id: 'ver_auditoria', nome: 'Ver Auditoria', descricao: 'Visualizar logs de ações' }
  ];

  const validar = () => {
    const e = {};
    if (!form.nome) e.nome = 'Nome obrigatório';
    if (!form.email) e.email = 'E-mail obrigatório';
    if (modo === 'novo' && !form.senha) e.senha = 'Senha obrigatória';
    if (!form.cpf) e.cpf = 'CPF obrigatório';
    if (form.permissoes.length === 0) e.permissoes = 'Selecione pelo menos uma permissão';
    
    // Verificar e-mail duplicado
    if (equipe.membros?.some(t => t.email === form.email && t.id !== equipeSelecionada?.id)) {
      e.email = 'E-mail já cadastrado nesta equipe';
    }
    
    return e;
  };

  const handleSalvar = () => {
    const e = validar();
    if (Object.keys(e).length) {
      setErros(e);
      return;
    }

    const membrosAtualizados = [...(equipe.membros || [])];

    if (modo === 'novo') {
      const novoMembro = {
        ...form,
        id: `membro_${Date.now()}`,
        ativo: true,
        dataCadastro: new Date().toISOString(),
        ultimoAcesso: null
      };
      
      membrosAtualizados.push(novoMembro);
      
      if (registrarAcao) registrarAcao(usuarioLogado?.id, usuarioLogado?.nome, "Adicionou membro", novoMembro.nome, null, { equipeId: equipe.id, modulo: "membros" });
    } else {
      const index = membrosAtualizados.findIndex(t => t.id === equipeSelecionada.id);
      if (index >= 0) {
        membrosAtualizados[index] = {
          ...equipeSelecionada,
          ...form,
          senha: form.senha || equipeSelecionada.senha // Manter senha se não alterou
        };
        
        if (registrarAcao) registrarAcao(usuarioLogado?.id, usuarioLogado?.nome, "Editou membro", form.nome, null, { equipeId: equipe.id, modulo: "membros" });
      }
    }

    const equipeatualizada = {
      ...equipe,
      membros: membrosAtualizados
    };

    atualizarEquipe(equipeatualizada);
    
    setModo('lista');
    setForm({ nome: '', email: '', senha: '', cpf: '', telefone: '', cargo: '', permissoes: [] });
    setEquipeSelecionada(null);
    setErros({});
  };

  const handleEditar = (membro) => {
    setEquipeSelecionada(membro);
    setForm({
      nome: membro.nome,
      email: membro.email,
      senha: '',
      cpf: membro.cpf || '',
      telefone: membro.telefone || '',
      cargo: membro.cargo || '',
      permissoes: membro.permissoes || []
    });
    setModo('editar');
  };

  const handleRemover = (equipeId) => {
    const membro = equipe.equipes?.find(t => t.id === equipeId);
    
    if (!confirm(`⚠️ Excluir membro "${membro.nome}"?\n\nEsta ação é IRREVERSÍVEL!`)) {
      return;
    }

    const equipeatualizada = {
      ...equipe,
      membros: equipe.equipes?.filter(t => t.id !== equipeId)
    };

    atualizarEquipe(equipeatualizada);
    
    if (registrarAcao) registrarAcao(usuarioLogado?.id, usuarioLogado?.nome, "Removeu membro", membro.nome, null, { equipeId: equipe.id, modulo: "membros" });
  };

  const togglePermissao = (permissaoId) => {
    setForm(prev => ({
      ...prev,
      permissoes: prev.permissoes.includes(permissaoId)
        ? prev.permissoes.filter(p => p !== permissaoId)
        : [...prev.permissoes, permissaoId]
    }));
  };

  return (
    <div style={styles.page}>
      <div style={styles.painelHeader}>
        <div>
          <h1 style={styles.pageTitle}>👥 Gerenciar Membros</h1>
          <p style={{ color: '#666', fontSize: 14 }}>
            Adicione e gerencie membros da equipe {equipe.nome}
          </p>
        </div>
        <button style={styles.btnGhost} onClick={() => setTela('painel-equipe')}>
          ← Voltar
        </button>
      </div>

      {/* Botão Adicionar */}
      {modo === 'lista' && (
        <button 
          style={styles.btnPrimary}
          onClick={() => setModo('novo')}
        >
          + Adicionar Membro
        </button>
      )}

      {/* Formulário */}
      {(modo === 'novo' || modo === 'editar') && (
        <div style={{
          background: '#0D0E12',
          border: '1px solid #1E2130',
          borderRadius: 12,
          padding: 32,
          marginTop: 24,
          maxWidth: 800
        }}>
          <h3 style={{ color: '#1976D2', marginBottom: 24 }}>
            {modo === 'novo' ? '➕ Novo Membro' : '✏️ Editar Membro'}
          </h3>

          <div style={{ display: 'grid', gap: 16 }}>
            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 6 }}>
                Nome Completo *
              </label>
              <input
                type="text"
                value={form.nome}
                onChange={(e) => setForm({ ...form, nome: e.target.value })}
                style={{ ...styles.input, borderColor: erros.nome ? '#ff6b6b' : undefined }}
              />
              {erros.nome && <div style={{ color: '#ff6b6b', fontSize: 12, marginTop: 4 }}>{erros.nome}</div>}
            </div>

            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 6 }}>
                E-mail *
              </label>
              <input
                type="email"
                value={form.email}
                onChange={(e) => setForm({ ...form, email: e.target.value })}
                style={{ ...styles.input, borderColor: erros.email ? '#ff6b6b' : undefined }}
              />
              {erros.email && <div style={{ color: '#ff6b6b', fontSize: 12, marginTop: 4 }}>{erros.email}</div>}
            </div>

            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 6 }}>
                Senha {modo === 'editar' && '(deixe em branco para manter)'}
              </label>
              <input
                type="password"
                value={form.senha}
                onChange={(e) => setForm({ ...form, senha: e.target.value })}
                style={{ ...styles.input, borderColor: erros.senha ? '#ff6b6b' : undefined }}
              />
              {erros.senha && <div style={{ color: '#ff6b6b', fontSize: 12, marginTop: 4 }}>{erros.senha}</div>}
            </div>

            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 6 }}>
                CPF *
              </label>
              <input
                type="text"
                value={form.cpf}
                onChange={(e) => setForm({ ...form, cpf: e.target.value })}
                placeholder="000.000.000-00"
                style={{ ...styles.input, borderColor: erros.cpf ? '#ff6b6b' : undefined }}
              />
              {erros.cpf && <div style={{ color: '#ff6b6b', fontSize: 12, marginTop: 4 }}>{erros.cpf}</div>}
            </div>

            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 6 }}>
                Cargo/Função
              </label>
              <input
                type="text"
                value={form.cargo}
                onChange={(e) => setForm({ ...form, cargo: e.target.value })}
                placeholder="Ex: Técnico Principal, Assistente..."
                style={styles.input}
              />
            </div>

            {/* Permissões */}
            <div>
              <label style={{ display: 'block', color: '#aaa', fontSize: 13, marginBottom: 12 }}>
                Permissões *
              </label>
              <div style={{ display: 'grid', gap: 12 }}>
                {PERMISSOES_DISPONIVEIS.map(perm => (
                  <div key={perm.id} style={{
                    background: form.permissoes.includes(perm.id) ? '#1a2a1a' : '#141720',
                    border: `2px solid ${form.permissoes.includes(perm.id) ? '#7cfc7c' : '#1E2130'}`,
                    borderRadius: 8,
                    padding: 16,
                    cursor: 'pointer',
                    transition: 'all 0.2s'
                  }}
                  onClick={() => togglePermissao(perm.id)}
                  >
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      <div style={{
                        width: 20,
                        height: 20,
                        borderRadius: 4,
                        border: '2px solid #7cfc7c',
                        background: form.permissoes.includes(perm.id) ? '#7cfc7c' : 'transparent',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        color: '#000',
                        fontWeight: 700
                      }}>
                        {form.permissoes.includes(perm.id) && '✓'}
                      </div>
                      <div style={{ flex: 1 }}>
                        <div style={{ color: '#fff', fontWeight: 600, marginBottom: 4 }}>
                          {perm.nome}
                        </div>
                        <div style={{ color: '#888', fontSize: 12 }}>
                          {perm.descricao}
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              {erros.permissoes && <div style={{ color: '#ff6b6b', fontSize: 12, marginTop: 8 }}>{erros.permissoes}</div>}
            </div>
          </div>

          <div style={{ display: 'flex', gap: 12, marginTop: 24 }}>
            <button
              style={styles.btnGhost}
              onClick={() => {
                setModo('lista');
                setForm({ nome: '', email: '', senha: '', cpf: '', telefone: '', cargo: '', permissoes: [] });
                setErros({});
              }}
            >
              Cancelar
            </button>
            <button style={styles.btnPrimary} onClick={handleSalvar}>
              {modo === 'novo' ? '✓ Adicionar' : '✓ Salvar Alterações'}
            </button>
          </div>
        </div>
      )}

      {/* Lista */}
      {modo === 'lista' && (
        <div style={{ marginTop: 24, display: 'grid', gap: 16 }}>
          {(equipe.membros || []).map(membro => (
            <div key={membro.id} style={{
              background: '#0D0E12',
              border: '1px solid #1E2130',
              borderRadius: 12,
              padding: 24,
              display: 'flex',
              alignItems: 'center',
              gap: 20
            }}>
              <div style={{ flex: 1 }}>
                <div style={{ color: '#fff', fontSize: 18, fontWeight: 600, marginBottom: 4 }}>
                  {membro.nome}
                </div>
                <div style={{ color: '#888', fontSize: 14, marginBottom: 8 }}>
                  📧 {membro.email} {membro.cargo && `• ${membro.cargo}`}
                </div>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                  {membro.permissoes.map(permId => {
                    const perm = PERMISSOES_DISPONIVEIS.find(p => p.id === permId);
                    return perm ? (
                      <span key={permId} style={{
                        background: '#1a2a1a',
                        color: '#7cfc7c',
                        padding: '4px 12px',
                        borderRadius: 4,
                        fontSize: 12,
                        border: '1px solid #7cfc7c44'
                      }}>
                        {perm.nome}
                      </span>
                    ) : null;
                  })}
                </div>
                <div style={{ color: '#666', fontSize: 12, marginTop: 8 }}>
                  Status: <span style={{ color: membro.ativo ? '#7cfc7c' : '#ff6b6b' }}>
                    {membro.ativo ? 'Ativo' : 'Inativo'}
                  </span>
                </div>
              </div>

              <div style={{ display: 'flex', gap: 8 }}>
                <button
                  style={styles.btnSecondary}
                  onClick={() => handleEditar(membro)}
                >
                  ✏️ Editar
                </button>
                <button
                  style={styles.btnGhost}
                  onClick={() => handleRemover(membro.id)}
                >
                  🗑️ Remover
                </button>
              </div>
            </div>
          ))}

          {(!equipe.membros || (equipe.membros || []).length === 0) && (
            <div style={{ textAlign: 'center', padding: 60, color: '#666' }}>
              <div style={{ fontSize: 64, marginBottom: 16 }}>👨‍🏫</div>
              <div style={{ fontSize: 18 }}>Nenhum membro cadastrado</div>
              <div style={{ fontSize: 14, marginTop: 8 }}>
                Clique em "Adicionar Membro" para começar
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}


// ═══════════════════════════════════════════════════════════════════════════
// COMPONENTE: AUDITORIA
// ═══════════════════════════════════════════════════════════════════════════

function TelaAuditoria({ usuarioLogado, setTela, historicoAcoes }) {
  const { equipe } = usuarioLogado;
  const [filtro, setFiltro] = useState('todos');
  const [busca, setBusca] = useState('');

  const auditoriaEquipe = (historicoAcoes || [])
    .filter(a => a.equipeId === equipe?.id)
    .sort((a, b) => new Date(b.data) - new Date(a.data));

  const agora = new Date();
  const auditoriaFiltrada = auditoriaEquipe.filter(registro => {
    const dataRegistro = new Date(registro.data);
    switch(filtro) {
      case 'hoje': return dataRegistro.toDateString() === agora.toDateString();
      case 'semana': { const d = new Date(agora); d.setDate(agora.getDate() - 7); return dataRegistro >= d; }
      case 'mes': { const d = new Date(agora); d.setMonth(agora.getMonth() - 1); return dataRegistro >= d; }
      default: return true;
    }
  }).filter(registro => {
    if (!busca) return true;
    const b = busca.toLowerCase();
    return (registro.nomeUsuario?.toLowerCase().includes(b) || registro.acao?.toLowerCase().includes(b) || registro.detalhe?.toLowerCase().includes(b) || registro.modulo?.toLowerCase().includes(b));
  });

  const formatarDataHora = (ts) => {
    const data = new Date(ts);
    const hoje = new Date();
    const horaStr = data.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' });
    if (data.toDateString() === hoje.toDateString()) return `Hoje às ${horaStr}`;
    const ontem = new Date(hoje); ontem.setDate(hoje.getDate() - 1);
    if (data.toDateString() === ontem.toDateString()) return `Ontem às ${horaStr}`;
    return `${data.toLocaleDateString("pt-BR")} às ${horaStr}`;
  };

  const getModuloIcon = (mod) => ({ equipes:"🏢", atletas:"🏃", competicoes:"🏟️", inscricoes:"📝", resultados:"📊", sumulas:"📋", recordes:"🏆", numeracao:"🔢", membros:"👥", treinadores:"👨‍🏫", funcionarios:"👷", auth:"🔐", sistema:"⚙️" }[mod] || "📋");

  return (
    <div style={styles.page}>
      <div style={styles.painelHeader}>
        <div>
          <h1 style={styles.pageTitle}>📊 Auditoria de Ações</h1>
          <p style={{ color: '#666', fontSize: 14 }}>Histórico de ações da equipe {equipe?.nome}</p>
        </div>
        <button style={styles.btnGhost} onClick={() => setTela('painel-equipe')}>← Voltar</button>
      </div>
      <div style={{ background:"#0D0E12", border:"1px solid #1E2130", borderRadius:12, padding:24, marginBottom:24 }}>
        <div style={{ display:"flex", gap:16, flexWrap:"wrap", alignItems:"center" }}>
          <div style={{ flex:"1 1 300px" }}>
            <label style={{ display:"block", color:"#aaa", fontSize:13, marginBottom:8 }}>Período:</label>
            <div style={{ display:"flex", gap:8 }}>
              {[{ id:"todos", label:"Todos" },{ id:"hoje", label:"Hoje" },{ id:"semana", label:"7 dias" },{ id:"mes", label:"30 dias" }].map(o => (
                <button key={o.id} onClick={() => setFiltro(o.id)} style={{ padding:"8px 16px", background: filtro===o.id ? "#1976D2" : "#141720", color: filtro===o.id ? "#000" : "#aaa", border:`1px solid ${filtro===o.id ? "#1976D2" : "#1E2130"}`, borderRadius:6, cursor:"pointer", fontSize:13, fontWeight: filtro===o.id ? 600 : 400 }}>{o.label}</button>
              ))}
            </div>
          </div>
          <div style={{ flex:"1 1 300px" }}>
            <label style={{ display:"block", color:"#aaa", fontSize:13, marginBottom:8 }}>Buscar:</label>
            <input type="text" value={busca} onChange={e => setBusca(e.target.value)} placeholder="Buscar por usuário, ação ou detalhe..." style={styles.input} />
          </div>
        </div>
        <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(150px, 1fr))", gap:16, marginTop:20, paddingTop:20, borderTop:"1px solid #1E2130" }}>
          <div style={{ textAlign:"center" }}><div style={{ fontSize:32, fontWeight:700, color:"#1976D2" }}>{auditoriaFiltrada.length}</div><div style={{ color:"#888", fontSize:12 }}>Registros</div></div>
          <div style={{ textAlign:"center" }}><div style={{ fontSize:32, fontWeight:700, color:"#7cfc7c" }}>{new Set(auditoriaFiltrada.map(a => a.nomeUsuario)).size}</div><div style={{ color:"#888", fontSize:12 }}>Usuários</div></div>
          <div style={{ textAlign:"center" }}><div style={{ fontSize:32, fontWeight:700, color:"#88aaff" }}>{new Set(auditoriaFiltrada.map(a => a.modulo).filter(Boolean)).size}</div><div style={{ color:"#888", fontSize:12 }}>Módulos</div></div>
        </div>
      </div>
      <div style={{ display:"grid", gap:8 }}>
        {auditoriaFiltrada.length === 0 ? (
          <div style={{ background:"#0D0E12", border:"1px solid #1E2130", borderRadius:12, padding:60, textAlign:"center" }}>
            <div style={{ fontSize:64, marginBottom:16 }}>📊</div>
            <div style={{ color:"#aaa", fontSize:16 }}>Nenhum registro encontrado</div>
          </div>
        ) : auditoriaFiltrada.map(reg => (
          <div key={reg.id} style={{ background:"#0D0E12", border:"1px solid #1E2130", borderRadius:8, padding:"12px 16px", display:"flex", gap:12, alignItems:"center" }}>
            <span style={{ fontSize:20, flexShrink:0 }}>{getModuloIcon(reg.modulo)}</span>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ color:"#fff", fontSize:13, fontWeight:600 }}>{reg.acao}</div>
              {reg.detalhe && <div style={{ color:"#888", fontSize:11, whiteSpace:"nowrap", overflow:"hidden", textOverflow:"ellipsis" }}>{reg.detalhe}</div>}
            </div>
            <div style={{ textAlign:"right", flexShrink:0 }}>
              <div style={{ color:"#1976D2", fontSize:11, fontWeight:600 }}>{reg.nomeUsuario || "—"}</div>
              <div style={{ color:"#555", fontSize:10 }}>{formatarDataHora(reg.data)}</div>
            </div>
            {reg.modulo && <span style={{ padding:"2px 8px", borderRadius:4, fontSize:9, background:"#141720", color:"#666", border:"1px solid #1E2130", flexShrink:0 }}>{reg.modulo}</span>}
          </div>
        ))}
      </div>
      {auditoriaFiltrada.length > 0 && (
        <div style={{ marginTop:24, padding:16, background:"#0D0E12", border:"1px solid #1E2130", borderRadius:8, textAlign:"center", color:"#666", fontSize:12 }}>
          Mostrando {auditoriaFiltrada.length} de {auditoriaEquipe.length} registro(s) · Máximo 2000 registros mantidos
        </div>
      )}
    </div>
  );





}
export default App;

